static int __stdcall _sti_wia_IID_Lookup(const IID* pIID, int* pIndex)
{
    int low = 0, high = 4;

    while (low <= high)
    {
        int pos = (low + high) / 2;
        int res = IID_GENERIC_CHECK_IID(_sti_wia, pIID, pos);
        if (!res) { *pIndex = pos; return 1; }
        if (res > 0) low = pos + 1;
        else high = pos - 1;
    }
    return 0;
}

